pipeline.evaluate:
(() => {
  const limit = parseInt('${{ args.limit }}');
  const items = [];
  const seen = new Set();
  const cells = document.querySelectorAll('[data-testid="trend"]');

  const normalize = (text) => (text || '').replace(/\s+/g, ' ').trim();
  const isNoise = (text) => {
    if (!text) return true;
    if (text === '·' || /^·+$/.test(text)) return true;
    if (/^\d+$/.test(text)) return true;
    if (/^(show more|what's happening)$/i.test(text)) return true;
    if (/posts?$/i.test(text) || /Trending$/i.test(text)) return true;
    return false;
  };

  cells.forEach(cell => {
    const text = cell.textContent || '';
    if (text.includes('Promoted')) return;

    const category = normalize(Array.from(cell.querySelectorAll('span'))
      .map(span => normalize(span.textContent || ''))
      .find(value => value && /(?:Trending|Business|Technology|Sports|Politics|Entertainment|News)$/i.test(value)) || '');

    const countMatch = text.match(/([\d.,]+\s*[KMB]?)[\s\u00a0]+posts?/i);
    const tweets = countMatch ? countMatch[1].replace(/\s+/g, '') : 'N/A';

    let topic = '';
    const link = cell.querySelector('a[href*="/search?q="], a[href*="/hashtag/"]');
    if (link) {
      topic = normalize(link.textContent || '');
    }
    if (!topic || isNoise(topic)) {
      const candidates = Array.from(cell.querySelectorAll('span'))
        .map(span => normalize(span.textContent || ''))
        .filter(value => !isNoise(value));
      topic = candidates.find(value => value.startsWith('#') || /[A-Za-z\u4e00-\u9fff0-9]/.test(value)) || '';
    }

    if (topic && !seen.has(topic)) {
      seen.add(topic);
      items.push({ rank: items.length + 1, topic, tweets, category });
    }
  });

  return items.slice(0, limit);
})()
